637	\section{Definitions, and the two delimitations}\label{sec:noslack}
638	
639	\begin{definition}[Support-wise agreement]\label{def:sclose}
640	For $C\subseteq\F^D$, $|D|=n$, $\delta\in[0,1]$: a word $u\in\F^D$ is \emph{$S$-close} to $C$ at radius $\delta$ if $S\subseteq D$, $|S|\ge(1-\delta)n$, and $u|_S=c|_S$ for some $c\in C$.
641	\end{definition}
642	
643	\begin{definition}[Bad parameter and line-MCA error]\label{def:mca}
644	For a line $u_z=f+zg$, $z\in\F$: the parameter $z$ is \emph{support-wise MCA-bad} at radius $\delta$ if there is $S\subseteq D$ with (i) $u_z$ $S$-close to $C$ at radius $\delta$, and (ii) no pair $c_f,c_g\in C$ satisfying $f|_S=c_f|_S$ and $g|_S=c_g|_S$.  Then
645	\[
646	        \emca(C,\delta)\ =\ \max_{f,g\in\F^D}\ \frac1{|\F|}\,\#\{z:\ z\text{ support-wise MCA-bad for }f+zg\},
647	\]
648	and the threshold is
649	\[
650	        \delta^*_C(\eps^*)=\sup\{\delta:\emca(C,\delta)\le\eps^*\}.
651	\]
652	A witness at radius $\delta$ is one at every larger radius (neither condition mentions $\delta$ otherwise), so $\emca(C,\cdot)$ is nondecreasing and error one propagates upward; this is the monotonicity lemma of \cite{NoSlack}.
653	\end{definition}
654	
